int main() {
    Point p;
    p.setX(10);
    p.setY(20);
    std::cout << "Point coordinates: (" << p.getX() << ", " << p.getY() << ")\n";

    p.setX(-5); // Should be clamped to 0
    p.setY(15);
    std::cout << "Point coordinates: (" << p.getX() << ", " << p.getY() << ")\n";

    p.setX(30);
    p.setY(-10); // Should be clamped to 0
    std::cout << "Point coordinates: (" << p.getX() << ", " << p.getY() << ")\n";

    return 0;
}
